#include <bits/stdc++.h>
using namespace std;

const int T=1e6+6,N=2.5e4+4;

struct Node{
    int s,e;
}a[N];

bool cmp(Node x,Node y){
    return x.e<y.e;
}

int n,len,f[T],t[4*T];

void build(int cur,int l,int r){
    if(l==r){
        t[cur]=f[l];
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=min(t[cur*2],t[cur*2+1]);
}

int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1,ans=2e9;
    if(x<=mid)
        ans=min(ans,query(cur*2,l,mid,x,y));
    if(y>mid)
        ans=min(ans,query(cur*2+1,mid+1,r,x,y));
    return ans;
}

void modify(int cur,int l,int r,int x,int y){
    if(l==r && l==x){
        f[x]=t[cur]=y;
        return;
    }
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y);
    else
        modify(cur*2+1,mid+1,r,x,y);
    t[cur]=min(t[cur*2],t[cur*2+1]);
}

int main(){
    scanf("%d%d",&n,&len);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&a[i].s,&a[i].e);

    sort(a+1,a+n+1,cmp);
    memset(f,127,sizeof(f));
    f[0]=0;
    build(1,0,len);
    for(int i=1;i<=n;i++)
        modify(1,0,len,a[i].e,min(f[a[i].e],query(1,0,len,a[i].s-1,a[i].e-1)+1));
    if(f[len]>n)
        printf("-1");
    else
        printf("%d",f[len]);
    return 0;
}
